const bible = $('Read Operating Bible').first().json.content || '';

// Extract just Part II (What We Build) and Part VIII (Identifying New Businesses) sections
// to keep the prompt focused and within token limits
const partII = bible.match(/# Part II:.*?(?=# Part III:)/s)?.[0] || '';
const partVIII = bible.match(/# Part VIII:.*?(?=# Part IX:)/s)?.[0] || '';

return [{
  json: {
    prompt: `Today is ${new Date().toISOString().split('T')[0]}. You are the Discovery Engine for The Forge (Forge Technologies).

Your job: score new business opportunities across all five sourcing tiers.

## What We Build (from Operating Bible)
${partII}

## How We Find Ideas (from Operating Bible)
${partVIII}

## Your Task
Generate 5-10 business opportunity ideas that pass the Double Filter (Revenue Ceiling Test + Distribution Test). For each, provide:

1. **Name/Concept:** Brief description
2. **Category:** SMB Vertical Tool / Prosumer Workflow / PLG Platform
3. **Sourcing Tier:** Which tier this came from (1-5)
4. **Target Market:** Who buys this, how many exist
5. **Pricing Model:** Proposed tiers
6. **Distribution Viability:** Key SEO keywords + estimated monthly search volume. Reel potential (what would a demo video show?)
7. **Revenue Ceiling Test:** Can this reach $100K MRR? Show the math.
8. **Competition:** Who exists, what are their weaknesses (from reviews)
9. **Score (1-10):** Weighted across: demand evidence, AI build feasibility, monetization clarity, competition gap, distribution viability

Only surface ideas scoring 6.5+. Be specific about keyword volumes and competition. Use real examples from known markets.

Output as structured markdown.`
  }
}];
